#include<bits/stdc++.h>
using namespace std;

const int N = 1e4 + 5;
const int M = 1e5 + 5;

int fa[N], c[N];

int find(int x)
{
    return x == fa[x] ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
    fa[find(x)] = find(y);
}

struct Edge
{
    int u, v, w;
    void read()
    {
        cin >> u >> v >> w;
    }
}e[M];

bool cmp(Edge x, Edge y)
{
    return x.w < y.w;
}

int main()
{
    int n, m, ans = 0, cnt = 0, minn = 2e9;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        fa[i] = i;
    for(int i = 1; i <= n; i++)
    {
    	cin >> c[i];
    	minn = min(minn, c[i]);
    }
    for(int i = 1; i <= m; i++)
    {
        e[i].read();
        e[i].w = c[e[i].u] + c[e[i].v] + 2 * e[i].w;
    }
    sort(e + 1, e + m + 1, cmp);
    for(int i = 1; i <= m; i++)
    {
        int u = e[i].u, v = e[i].v, w = e[i].w;
        if(find(u) != find(v))
        {
            ans += w;
            merge(u, v);
        }
    }
    cout << ans + minn;
}
